const PageEvents=(()=>{function init(){loadEvents()}function loadEvents(){const list=document.querySelector('[data-content="events-list"]');if(!list)return;list.innerHTML='<div class="empty-state"><p>'+LanguageEngine.t("loading")+"</p></div>";ApiClient.getEvents().then(events=>{if(!events||events.length===0){list.innerHTML='<div class="empty-state"><p>'+LanguageEngine.t("empty_events")+"</p></div>";return}list.innerHTML=events.map(e=>{const l=CoreUtils.lang();const months=LanguageEngine.t("calendar_month_5").split(" ");const d=new Date(e.date+"T00:00:00");const day=d.getDate();const month=d.toLocaleString(l==="ha"?"fr":l,{month:"short"});return'<div class="event-card anim-hidden">'+'<div class="event-date-box"><div class="day">'+day+'</div><div class="month">'+month+"</div></div>"+'<div class="event-info">'+"<h3>"+CoreUtils.esc(e["title_"+l]||e.title_fr)+"</h3>"+'<div class="event-meta">'+'<span><svg fill="none" stroke="currentColor" viewBox="0 0 24 24" width="14" height="14" style="display:inline;vertical-align:middle;margin-right:2px"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"/><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"/></svg>'+CoreUtils.esc(e["location_"+l]||e.location_fr)+"</span>"+"<span>"+CoreUtils.esc(e.date)+"</span>"+"</div>"+"<p>"+CoreUtils.esc((e["description_"+l]||e.description_fr).substring(0,200))+"</p>"+"</div></div>"}).join("")}).catch(()=>{list.innerHTML='<div class="empty-state"><p>'+LanguageEngine.t("error_network")+"</p></div>"})}document.addEventListener("languageChanged",loadEvents);document.addEventListener("dataChanged",e=>{if(!e.detail||e.detail.type==="events")loadEvents()});return{init:init}})();window.PageEvents=PageEvents;